[{"title": "水煮鱼", "description": "鲜嫩鱼片在红油中翻滚", "category": "chinese", "season": "winter", "difficulty": "hard", "cookTime": 40, "servings": 4, "isFeatured": 1, "coverImage": "https://images.unsplash.com/photo-1583223667854-e0e05b2ad1e8?w=800", "ingredients": [{"name": "草鱼", "amount": 1, "unit": "条"}, {"name": "豆芽", "amount": 200, "unit": "g"}, {"name": "干辣椒", "amount": 30, "unit": "g"}, {"name": "花椒", "amount": 10, "unit": "g"}, {"name": "郫县豆瓣酱", "amount": 2, "unit": "勺"}, {"name": "料酒", "amount": 2, "unit": "勺"}, {"name": "蛋清", "amount": 1, "unit": "个"}, {"name": "蒜", "amount": 6, "unit": "瓣"}], "steps": [{"stepNumber": 1, "content": "草鱼片成薄片，用料酒、蛋清、淀粉腌制15分钟"}, {"stepNumber": 2, "content": "豆芽焯水铺在大碗底部"}, {"stepNumber": 3, "content": "锅中热油，下豆瓣酱炒出红油，加姜蒜爆香"}, {"stepNumber": 4, "content": "加水烧开，放入鱼片煮至变色"}, {"stepNumber": 5, "content": "鱼片捞出铺在豆芽上，浇入汤汁"}, {"stepNumber": 6, "content": "撒干辣椒段和花椒，浇热油激香"}], "nutrition": {"calories": 380, "protein": 32, "fat": 24, "carbs": 8, "fiber": 2, "sodium": 920}, "tips": "鱼片不要煮太久，变色即可捞出。最后浇热油不能省。", "categoryTags": {"ingredient": ["鱼", "豆芽"], "method": ["水煮"], "cuisine": ["川菜"], "flavor": ["麻辣"], "price": ["中等"]}}]